namespace sv_8a40e0d36fd04b4389f1f2cd64dc958d.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Fired whenever Theme or AccentColor changes.
    /// Each subscriber (component) should call StateHasChanged in its handler.
    /// </summary>
    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" style="color: @ThemeService.AccentColor;">
    @GetIcon() @ThemeService.Theme
</span>

<button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
    Toggle Theme
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px; border-color: @ThemeService.AccentColor;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                        style="@(ThemeService.Theme == mode ? $"background-color:{ThemeService.AccentColor};border-color:{ThemeService.AccentColor};" : "")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </div>

        <p class="text-muted mt-3">
            Current: <strong>@ThemeService.Theme</strong> / <strong>@ThemeService.AccentColor</strong>
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

